 16	import {
 17	  PersesDashboardWrapper,
 18	  PersesTempoDatasourceWrapper,
 19	  PersesWrapper,
 20	  TraceQueryPanelWrapper,
 21	} from '../components/PersesWrapper';
 22	import { TraceAttributeValue } from '@perses-dev/core';
 23	import { useDataQueries } from '@perses-dev/plugin-system';
 24	import { useTempoInstance } from '../hooks/useTempoInstance';
 25	import { QueryParamProvider } from 'use-query-params';
 26	import { ReactRouterAdapter } from '../react_router_adapter';
 27	
 28	export default function TraceDetailPage() {
 29	  const { t } = useTranslation('plugin__distributed-tracing-console-plugin');
 30	  const { traceId } = useParams();
 31	
 32	  return (
 33	    <QueryParamProvider adapter={ReactRouterAdapter}>
 34	      <HelmetProvider>
 35	        <Helmet>
 36	          <title>
 37	            {t('Trace')} {traceId} · {t('Tracing')}
 38	          </title>
 39	        </Helmet>
 40	      </HelmetProvider>
 41	      <Page>
 42	        <TraceDetailPageBody />
 43	      </Page>
 44	    </QueryParamProvider>
 45	  );
 46	}
 47	
 48	function TraceDetailPageBody() {
 49	  const { t } = useTranslation('plugin__distributed-tracing-console-plugin');
 50	  const { traceId } = useParams();
 51	  const [tempo] = useTempoInstance();
 52	  const location = useLocation();
 53	
 54	  return (
 55	    <PageSection variant="light">
 56	      <Stack>
 57	        <Breadcrumb>
 58	          <BreadcrumbItem>
 59	            <Link to={`/observe/traces${location.search}`}>{t('Traces')}</Link>
 60	          </BreadcrumbItem>
 61	          <BreadcrumbItem isActive>{t('Trace details')}</BreadcrumbItem>
 62	        </Breadcrumb>
 63	
 64	        <PersesWrapper>
 65	          <PersesDashboardWrapper>
 66	            <PersesTempoDatasourceWrapper
 67	              tempo={tempo}
 68	              queries={[{ kind: 'TempoTraceQuery', spec: { query: traceId } }]}
 69	            >
 70	              <Title headingLevel="h1">
 71	                <TraceTitle />
 72	              </Title>
 73	              <Divider className="pf-v6-u-my-md" />
 74	              <StackItem isFilled>
 75	                <TraceQueryPanelWrapper>
 76	                  <TracingGanttChart.PanelComponent
 77	                    spec={{ visual: { palette: { mode: 'categorical' } } }}
 78	                    attributeLinks={attributeLinks}
 79	                  />
 80	                </TraceQueryPanelWrapper>
 81	              </StackItem>
 82	            </PersesTempoDatasourceWrapper>
 83	          </PersesDashboardWrapper>
 84	        </PersesWrapper>
 85	      </Stack>
 86	    </PageSection>
 87	  );
 88	}
 89	
 90	function TraceTitle() {
 91	  const { traceId } = useParams();
 92	  const { queryResults } = useDataQueries('TraceQuery');
 93	  const trace = queryResults[0]?.data?.trace;
 94	
 95	  if (!trace) {
 96	    return <>{traceId}</>;
 97	  }
 98	  return (
 99	    <>
100	      {trace.rootSpan.resource.serviceName}: {trace.rootSpan.name}
101	    </>
102	  );
103	}
104	
105	const sval = (val?: TraceAttributeValue) =>
106	  val && 'stringValue' in val ? encodeURIComponent(val.stringValue) : '';
107	
108	const attributeLinks: Record<string, (attrs: Record<string, TraceAttributeValue>) => string> = {
109	  'k8s.namespace.name': (attrs) => `/k8s/cluster/namespaces/${sval(attrs['k8s.namespace.name'])}`,
110	  'k8s.node.name': (attrs) => `/k8s/cluster/nodes/${sval(attrs['k8s.node.name'])}`,
111	  'k8s.deployment.name': (attrs) =>
112	    `/k8s/ns/${sval(attrs['k8s.namespace.name'])}/deployments/${sval(
113	      attrs['k8s.deployment.name'],
114	    )}`,
115	  'k8s.pod.name': (attrs) =>
116	    `/k8s/ns/${sval(attrs['k8s.namespace.name'])}/pods/${sval(attrs['k8s.pod.name'])}`,
117	};

